// Get all incoming items
const inputItems = $input.all();

let allCandles = [];
let symbol = null;

// Loop through inputs
for (const item of inputItems) {
    if (!item.json.data) continue;

    const datasets = item.json.data;

    for (const set of datasets) {
        if (!set.values || set.values.length === 0) continue;

        // Save symbol once
        if (!symbol && set.meta?.symbol) {
            symbol = set.meta.symbol;
        }

        const interval = set.meta?.interval || "";

        // Map raw values into standard candle structure
        const mapped = set.values.map(v => ({
            interval,
            isoTime: v.datetime,
            epochMs: new Date(v.datetime.replace(" ", "T") + "Z").getTime(),
            open: parseFloat(v.open),
            high: parseFloat(v.high),
            low: parseFloat(v.low),
            close: parseFloat(v.close)
        }));

        allCandles.push(...mapped);
    }
}

// SAFETY CHECK — if nothing parsed, stop early
if (allCandles.length === 0) {
    return [
        {
            json: {
                error: "NO_CANDLE_DATA",
                message: "Input JSON contained no usable candles."
            }
        }
    ];
}

// Sort candles by time ASC
allCandles.sort((a, b) => a.epochMs - b.epochMs);

// Latest valid close
const latest = allCandles[allCandles.length - 1];

// Return final structured output
return [
    {
        json: {
            symbol: symbol || "UNKNOWN",
            latestPrice: latest.close,
            latestTime: latest.isoTime,
            totalCandles: allCandles.length,
            candles: allCandles
        }
    }
];

